using namespace adsk::core;
using namespace adsk::fusion;

Ptr ui;

extern "C" XI_EXPORT bool run(const char* context)
{
    Ptr app = Application::get();
    if (!app)
        return false;

    ui = app->userInterface();
    if (!ui)
        return false;

    Ptr documents = app->documents();
    if (!documents)
        return false;

    Ptr doc = documents->add(DocumentTypes::FusionDesignDocumentType);
    if (!doc)
        return false;

    Ptr product = app->activeProduct();
    if (!product)
        return false;

    Ptr design = product;
    if (!design)
        return false;

    // Get the root component of the active design.
    Ptr rootComp = design->rootComponent();
    if (!rootComp)
        return false;

    // Create sketch circle on the xz plane.
    Ptr sketches = rootComp->sketches();
    if (!sketches)
        return false;
    Ptr sketch = sketches->add(rootComp->xZConstructionPlane());
    if (!sketch)
        return false;
    Ptr sketchCurves = sketch->sketchCurves();
    if (!sketchCurves)
        return false;
    Ptr sketchLines = sketchCurves->sketchLines();
    if (!sketchLines)
        return false;
    Ptr startPoint = Point3D::create(0, 0, 0);
    Ptr endPoint = Point3D::create(1.0, 0, 0);
    Ptr sketchLine = sketchLines->addByTwoPoints(startPoint, endPoint);
    Ptr endPoint2 = Point3D::create(0, 1.0, 0);
    Ptr sketchLine2 = sketchLines->addByTwoPoints(startPoint, endPoint2);

    // Create a open profile.
    Ptr openProfile = rootComp->createOpenProfile(sketchLine);
    Ptr openProfile2 = rootComp->createOpenProfile(sketchLine2);

    // Create an extrusion input.
    Ptr features = rootComp->features();
    if (!features)
        return false;
    Ptr extrudes = features->extrudeFeatures();
    if (!extrudes)
        return false;
    Ptr extrudeInput =
        extrudes->createInput(openProfile, FeatureOperations::NewBodyFeatureOperation);
    if (!extrudeInput)
        return false;
    extrudeInput->isSolid(false);
    Ptr extrudeInput2 =
        extrudes->createInput(openProfile2, FeatureOperations::NewBodyFeatureOperation);
    if (!extrudeInput2)
        return false;
    extrudeInput2->isSolid(false);

    // Define the extent.
    Ptr distance = ValueInput::createByReal(1.0);
    extrudeInput->setDistanceExtent(false, distance);
    extrudeInput2->setDistanceExtent(false, distance);

    // Create the extrusion.
    Ptr extrude = extrudes->add(extrudeInput);
    if (!extrude)
        return false;
    Ptr extrude2 = extrudes->add(extrudeInput2);
    if (!extrude2)
        return false;
    Ptr bodies = extrude->bodies();
    if (!bodies)
        return false;
    Ptr body = bodies->item(0);
    Ptr bodies2 = extrude2->bodies();
    if (!bodies2)
        return false;
    Ptr body2 = bodies2->item(0);
    Ptr surfaces = ObjectCollection::create();
    if (!surfaces)
        return false;
    surfaces->add(body);
    surfaces->add(body2);

    // Define tolerance with 1 cm.
    Ptr tolerance = ValueInput::createByReal(1.0);

    // Create a stitch input to be able to define the input needed for an stitch.
    Ptr stitches = features->stitchFeatures();
    if (!stitches)
        return false;
    Ptr stitchInput =
        stitches->createInput(surfaces, tolerance, FeatureOperations::NewBodyFeatureOperation);

    // Create a stitch feature.
    stitches->add(stitchInput);


    return true;
}
